// extractWindow caps how many of the most-recently-observed
// search_learnings rows the extractor considers per call. Keeping the
// window bounded keeps Extract O(1) in steady state.
const extractWindow = 50

// candidateKinds is the ordered set of lookup kinds Extract tries when
// searching for an entity_kind binding. Computed kinds are tried last
// because table-backed kinds carry the strongest "user meant this
// specific alias" signal. The list is deliberately short and CLI-
// neutral; a CLI that needs additional table-backed kinds can extend
// this slice by seeding rows under that kind via lookups.SeedFromConfig
// and adding the kind name to its own dispatch as needed.
//
// The set here is intentionally limited to the lookup kinds the
// generator can always emit safely (lowercase / uppercase / etc are
// computed and need no schema, "alias" is a generic catch-all that any
// CLI's seeded data can hang off). For CLI-specific kinds the consumer
// supplies via LearnConfig.EntityLookupSeeds, the recall integration
// passes those kinds through Opts.AdditionalKinds.
var candidateKinds = []string{
	// Computed kinds (no DB rows; pure transforms).
	"lowercase",
	"uppercase",
	"capitalize-first",
	"kebab-case",
	"slug",
}

// teachRow is the subset of search_learnings columns Extract reads.
// Kept locally so this package can stand alone without depending on
// the store package's column-set evolution.
type teachRow struct {
	queryPattern  string
	queryEntities []string
	resourceID    string
	resourceType  string
	venue         string
}

// Extract walks the most-recent search_learnings rows, groups them by
// structural signature, infers an entity-kind binding for each group,
// and writes one search_patterns row per successful inference. Returns
// the count of NEW rows created.
//
// Idempotent: re-running Extract on the same DB state produces zero
// new rows and bumps confidence on the matching existing rows.
//
// additionalKinds is the CLI-supplied list of table-backed lookup kinds
// (from LearnConfig.EntityLookupSeeds) that Extract should try ahead of
// the built-in computed kinds. Empty means computed-only.
func Extract(db *sql.DB, additionalKinds []string) (int, error) {
	if db == nil {
		return 0, fmt.Errorf("patterns.Extract: db is nil")
	}

	kinds := make([]string, 0, len(additionalKinds)+len(candidateKinds))
	for _, k := range additionalKinds {
		if k == "" {
			continue
		}
		kinds = append(kinds, k)
	}
	kinds = append(kinds, candidateKinds...)

	rows, err := db.Query(`SELECT query_pattern, COALESCE(query_entities, '[]'),
			COALESCE(resource_ids, '[]'), resource_type, COALESCE(venue, '')
		FROM search_learnings
		ORDER BY updated_at DESC
		LIMIT ?`, extractWindow)
	if err != nil {
		return 0, fmt.Errorf("patterns.Extract query: %w", err)
	}
	defer rows.Close()

	var teaches []teachRow
	for rows.Next() {
		var (
			qp, entJSON, idsJSON, rt, venue string
		)
		if err := rows.Scan(&qp, &entJSON, &idsJSON, &rt, &venue); err != nil {
			return 0, fmt.Errorf("patterns.Extract scan: %w", err)
		}
		ents, err := parseStringArray(entJSON)
		if err != nil || len(ents) != 1 {
			// Skip multi-entity rows (single-entity binding only) and
			// malformed-JSON rows.
			continue
		}
		ids, err := parseStringArray(idsJSON)
		if err != nil {
			continue
		}
		for _, rid := range ids {
			if rid == "" {
				continue
			}
			teaches = append(teaches, teachRow{
				queryPattern:  qp,
				queryEntities: ents,
				resourceID:    rid,
				resourceType:  rt,
				venue:         venue,
			})
		}
	}
	if err := rows.Err(); err != nil {
		return 0, fmt.Errorf("patterns.Extract rows: %w", err)
	}

	groups := map[groupKey][]teachRow{}
	for _, t := range teaches {
		structural := queryStructural(t.queryPattern, t.queryEntities[0])
		if structural == "" {
			continue
		}
		key := groupKey{
			queryPattern: structural,
			resourceType: t.resourceType,
			venue:        t.venue,
		}
		groups[key] = append(groups[key], t)
	}

	// Stable iteration order so test assertions on emitted recipes are
	// deterministic.
	keys := make([]groupKey, 0, len(groups))
	for k := range groups {
		keys = append(keys, k)
	}
	sort.Slice(keys, func(i, j int) bool {
		if keys[i].queryPattern != keys[j].queryPattern {
			return keys[i].queryPattern < keys[j].queryPattern
		}
		if keys[i].resourceType != keys[j].resourceType {
			return keys[i].resourceType < keys[j].resourceType
		}
		return keys[i].venue < keys[j].venue
	})

	created := 0
	for _, key := range keys {
		members := groups[key]
		if len(members) < 2 {
			continue
		}
		pat, ok := inferPattern(db, key, members, kinds)
		if !ok {
			continue
		}
		inserted, err := Upsert(db, pat)
		if err != nil {
			continue
		}
		if inserted {
			created++
		}
	}
	return created, nil
}

func inferPattern(db *sql.DB, key groupKey, members []teachRow, kinds []string) (Pattern, bool) {
	if len(members) == 0 {
		return Pattern{}, false
	}
	for _, kind := range kinds {
		if tmpl, ok := tryExactBinding(db, kind, members); ok {
			return Pattern{
				QueryTemplate:    buildQueryTemplate(key.queryPattern, members[0].queryEntities[0]),
				ResourceTemplate: tmpl,
				ResourceType:     key.resourceType,
				Venue:            key.venue,
				Strategy:         StrategySubstitute,
				EntityKind:       kind,
				Confidence:       DefaultConfidence,
				Source:           SourceInferred,
				ExampleQuery:     buildExampleQuery(key.queryPattern, members[0].queryEntities[0]),
				ExampleResource:  members[0].resourceID,
			}, true
		}
		if tmpl, ok := tryPrefixBinding(db, kind, members); ok {
			return Pattern{
				QueryTemplate:    buildQueryTemplate(key.queryPattern, members[0].queryEntities[0]),
				ResourceTemplate: tmpl,
				ResourceType:     key.resourceType,
				Venue:            key.venue,
				Strategy:         StrategySubstituteThenSearchPrefix,
				EntityKind:       kind,
				Confidence:       DefaultConfidence,
				Source:           SourceInferred,
				ExampleQuery:     buildExampleQuery(key.queryPattern, members[0].queryEntities[0]),
				ExampleResource:  members[0].resourceID,
			}, true
		}
	}
	return Pattern{}, false
}

func tryExactBinding(db *sql.DB, kind string, members []teachRow) (string, bool) {
	values := make([]string, len(members))
	for i, m := range members {
		v, ok, err := lookups.Lookup(db, kind, m.queryEntities[0])
		if err != nil || !ok || v == "" {
			return "", false
		}
		values[i] = v
	}
	first := members[0]
	idx := 0
	for {
		pos := strings.Index(first.resourceID[idx:], values[0])
		if pos < 0 {
			return "", false
		}
		pos += idx
		prefix := first.resourceID[:pos]
		suffix := first.resourceID[pos+len(values[0]):]

		allMatch := true
		for i, m := range members {
			if m.resourceID != prefix+values[i]+suffix {
				allMatch = false
				break
			}
		}
		if allMatch {
			return prefix + entitySlot(kind) + suffix, true
		}
		idx = pos + 1
		if idx >= len(first.resourceID) {
			return "", false
		}
	}
}

func tryPrefixBinding(db *sql.DB, kind string, members []teachRow) (string, bool) {
	values := make([]string, len(members))
	for i, m := range members {
		v, ok, err := lookups.Lookup(db, kind, m.queryEntities[0])
		if err != nil || !ok || v == "" {
			return "", false
		}
		values[i] = v
	}
	first := members[0]
	idx := 0
	for {
		pos := strings.Index(first.resourceID[idx:], values[0])
		if pos < 0 {
			return "", false
		}
		pos += idx
		prefix := first.resourceID[:pos]
		suffixFirst := first.resourceID[pos+len(values[0]):]

		sharedSuffix := suffixFirst
		ok := true
		for i := 1; i < len(members); i++ {
			m := members[i]
			if !strings.HasPrefix(m.resourceID, prefix) {
				ok = false
				break
			}
			if !strings.HasPrefix(m.resourceID[len(prefix):], values[i]) {
				ok = false
				break
			}
			suffixI := m.resourceID[len(prefix)+len(values[i]):]
			sharedSuffix = longestCommonPrefix(sharedSuffix, suffixI)
		}
		if !ok {
			idx = pos + 1
			if idx >= len(first.resourceID) {
				return "", false
			}
			continue
		}
		if sharedSuffix == "" {
			return "", false
		}
		if isFullyShared(sharedSuffix, suffixFirst, members, values, prefix) {
			// Exact in disguise; let tryExactBinding catch it.
			return "", false
		}
		return prefix + entitySlot(kind) + sharedSuffix + "*", true
	}
}

func isFullyShared(sharedSuffix, suffixFirst string, members []teachRow, values []string, prefix string) bool {
	if sharedSuffix != suffixFirst {
		return false
	}
	for i := 1; i < len(members); i++ {
		suffixI := members[i].resourceID[len(prefix)+len(values[i]):]
		if suffixI != sharedSuffix {
			return false
		}
	}
	return true
}

func queryStructural(queryPattern, entity string) string {
	tokens := strings.Fields(queryPattern)
	ent := strings.ToLower(strings.TrimSpace(entity))
	kept := make([]string, 0, len(tokens))
	for _, t := range tokens {
		if strings.ToLower(t) == ent {
			continue
		}
		kept = append(kept, t)
	}
	sort.Strings(kept)
	return strings.Join(kept, " ")
}

func buildQueryTemplate(queryPattern, entity string) string {
	structural := queryStructural(queryPattern, entity)
	tokens := strings.Fields(structural)
	tokens = append(tokens, "{entity}")
	sort.Strings(tokens)
	return strings.Join(tokens, " ")
}

func buildExampleQuery(queryPattern, entity string) string {
	if queryPattern == "" {
		return entity
	}
	return queryPattern + " " + entity
}

func entitySlot(kind string) string {
	return "{entity:" + kind + "}"
}

func longestCommonPrefix(a, b string) string {
	n := len(a)
	if len(b) < n {
		n = len(b)
	}
	for i := 0; i < n; i++ {
		if a[i] != b[i] {
			return a[:i]
		}
	}
	return a[:n]
}

func parseStringArray(raw string) ([]string, error) {
	raw = strings.TrimSpace(raw)
	if raw == "" || raw == "null" {
		return nil, nil
	}
	var out []string
	if err := json.Unmarshal([]byte(raw), &out); err != nil {
		return nil, err
	}
	return out, nil
}

type groupKey struct {
	queryPattern string
	resourceType string
	venue        string
}
